'use client';

import Link from 'next/link';
import { motion } from 'framer-motion';
import { Search, TrendingUp } from 'lucide-react';
import { mockArticles } from '@/data/articles';
import { mockTopics } from '@/data/topics';
import { formatNumber } from '@/lib/utils';
import { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function RightPanel() {
  const [searchQuery, setSearchQuery] = useState('');
  const router = useRouter();

  const trending = [...mockArticles]
    .sort((a, b) => (b.likesCount + b.commentsCount) - (a.likesCount + a.commentsCount))
    .slice(0, 5);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      router.push(`/?search=${encodeURIComponent(searchQuery.trim())}`);
    }
  };

  return (
    <aside className="fixed right-0 top-0 h-screen w-[350px] p-4 overflow-y-auto border-l max-xl:hidden z-40"
      style={{ background: '#000', borderColor: '#2F3336' }}
    >
      {/* Search */}
      <form onSubmit={handleSearch} className="relative mb-4">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: '#71767B' }} />
        <input
          type="text"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          placeholder="Tìm kiếm tin tức..."
          className="w-full pl-10 pr-4 py-2.5 rounded-full border text-sm transition-colors focus:outline-none"
          style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
          onFocus={(e) => (e.target.style.borderColor = '#F97316')}
          onBlur={(e) => (e.target.style.borderColor = '#2F3336')}
        />
      </form>

      {/* Trending */}
      <div className="rounded-2xl border mb-4 overflow-hidden" style={{ background: '#16181C', borderColor: '#2F3336' }}>
        <div className="px-4 py-3 flex items-center gap-2">
          <TrendingUp className="w-5 h-5" style={{ color: '#F97316' }} />
          <h2 className="text-lg font-bold" style={{ color: '#E7E9EA' }}>Xu hướng</h2>
        </div>
        {trending.map((article, i) => (
          <Link key={article.id} href={`/article/${article.id}`}>
            <motion.div
              whileHover={{ backgroundColor: 'rgba(255,255,255,0.03)' }}
              className="px-4 py-3 border-t cursor-pointer"
              style={{ borderColor: '#2F3336' }}
            >
              <div className="flex items-start justify-between gap-2">
                <div className="min-w-0 flex-1">
                  <p className="text-xs mb-0.5" style={{ color: '#71767B' }}>
                    {article.topic.icon} {article.topic.name} · Xu hướng
                  </p>
                  <p className="text-sm font-semibold leading-tight line-clamp-2" style={{ color: '#E7E9EA' }}>
                    {article.title}
                  </p>
                  <p className="text-xs mt-1" style={{ color: '#71767B' }}>
                    {formatNumber(article.likesCount + article.commentsCount)} lượt tương tác
                  </p>
                </div>
                <span className="text-lg font-bold shrink-0" style={{ color: '#2F3336' }}>
                  {i + 1}
                </span>
              </div>
            </motion.div>
          </Link>
        ))}
        <Link href="/trending">
          <div className="px-4 py-3 border-t text-sm transition-colors" style={{ borderColor: '#2F3336', color: '#F97316' }}>
            Xem thêm
          </div>
        </Link>
      </div>

      {/* Topics */}
      <div className="rounded-2xl border overflow-hidden" style={{ background: '#16181C', borderColor: '#2F3336' }}>
        <div className="px-4 py-3">
          <h2 className="text-lg font-bold" style={{ color: '#E7E9EA' }}>Chủ đề</h2>
        </div>
        <div className="px-4 pb-4 flex flex-wrap gap-2">
          {mockTopics.map((topic) => (
            <Link key={topic.slug} href={`/topic/${topic.slug}`}>
              <motion.span
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                className="inline-flex items-center gap-1 px-3 py-1.5 rounded-full text-sm font-medium transition-colors cursor-pointer border"
                style={{
                  borderColor: '#2F3336',
                  color: '#E7E9EA',
                  background: 'transparent',
                }}
              >
                {topic.icon} {topic.name}
              </motion.span>
            </Link>
          ))}
        </div>
      </div>

      {/* Footer */}
      <div className="mt-4 px-4">
        <p className="text-xs" style={{ color: '#536471' }}>
          © 2024 NewsX · Nền tảng tin tức thế hệ mới
        </p>
      </div>
    </aside>
  );
}
