'use client';

import { useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { ArrowLeft, Heart, Share2, Calendar, Shield, PenSquare, Eye } from 'lucide-react';
import Sidebar from '@/components/layout/Sidebar';
import RightPanel from '@/components/layout/RightPanel';
import MobileNav from '@/components/layout/MobileNav';
import ArticleCard from '@/components/feed/ArticleCard';
import { mockArticles } from '@/data/articles';
import { useAuth } from '@/contexts/AuthContext';
import { formatDate } from '@/lib/utils';

export default function ProfilePage() {
  const router = useRouter();
  const { currentUser, isAuthenticated, likes, shares } = useAuth();
  const [activeTab, setActiveTab] = useState<'shared' | 'liked'>('shared');

  if (!isAuthenticated || !currentUser) {
    router.push('/login');
    return null;
  }

  const likedArticles = mockArticles.filter((a) => likes.includes(a.id));
  const sharedArticles = mockArticles.filter((a) => shares.includes(a.id));
  const displayedArticles = activeTab === 'shared' ? sharedArticles : likedArticles;

  const roleBadge = {
    admin: { label: '🛡️ Admin', color: '#8B5CF6', bg: 'rgba(139,92,246,0.1)' },
    editor: { label: '✍️ Editor', color: '#3B82F6', bg: 'rgba(59,130,246,0.1)' },
    reader: { label: '👤 Reader', color: '#71767B', bg: 'rgba(113,118,123,0.1)' },
  }[currentUser.role];

  const tabs = [
    { key: 'shared', label: 'Đã chia sẻ', count: sharedArticles.length, icon: Share2 },
    { key: 'liked', label: 'Đã thích', count: likedArticles.length, icon: Heart },
  ] as const;

  return (
    <div className="min-h-screen" style={{ background: '#000' }}>
      <Sidebar />
      <main className="lg:ml-[275px] xl:mr-[350px] min-h-screen border-r" style={{ borderColor: '#2F3336' }}>
        {/* Header */}
        <div className="sticky top-0 z-30 flex items-center gap-4 px-4 py-3 border-b"
          style={{ background: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(12px)', borderColor: '#2F3336' }}
        >
          <button onClick={() => router.back()} className="p-2 rounded-full hover:bg-white/10" style={{ color: '#E7E9EA' }}>
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <h1 className="text-lg font-bold" style={{ color: '#E7E9EA' }}>{currentUser.name}</h1>
            <p className="text-xs" style={{ color: '#71767B' }}>{likedArticles.length + sharedArticles.length} bài viết</p>
          </div>
        </div>

        {/* Profile banner */}
        <div className="h-32 relative" style={{ background: 'linear-gradient(135deg, #F97316 0%, #EA580C 50%, #DC2626 100%)' }}>
          <div className="absolute -bottom-16 left-4">
            <div className="w-32 h-32 rounded-full border-4 overflow-hidden" style={{ borderColor: '#000', background: '#16181C' }}>
              <img src={currentUser.avatar} alt={currentUser.name} className="w-full h-full" />
            </div>
          </div>
        </div>

        {/* Profile info */}
        <div className="pt-20 px-4 pb-4 border-b" style={{ borderColor: '#2F3336' }}>
          <div className="flex items-start justify-between">
            <div>
              <h2 className="text-xl font-bold" style={{ color: '#E7E9EA' }}>{currentUser.name}</h2>
              <p className="text-sm" style={{ color: '#71767B' }}>{currentUser.email}</p>
            </div>
            <span className="px-3 py-1 rounded-full text-xs font-medium" style={{ background: roleBadge.bg, color: roleBadge.color }}>
              {roleBadge.label}
            </span>
          </div>
          {currentUser.bio && (
            <p className="mt-2 text-sm" style={{ color: '#E7E9EA' }}>{currentUser.bio}</p>
          )}
          <div className="flex items-center gap-2 mt-2">
            <Calendar className="w-4 h-4" style={{ color: '#71767B' }} />
            <span className="text-sm" style={{ color: '#71767B' }}>
              Tham gia {formatDate(currentUser.createdAt)}
            </span>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex border-b" style={{ borderColor: '#2F3336' }}>
          {tabs.map((tab) => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className="flex-1 py-3 text-sm font-medium relative flex items-center justify-center gap-2 transition-colors"
                style={{ color: activeTab === tab.key ? '#E7E9EA' : '#71767B' }}
              >
                <Icon className="w-4 h-4" />
                {tab.label} ({tab.count})
                {activeTab === tab.key && (
                  <motion.div
                    layoutId="profile-tab"
                    className="absolute bottom-0 left-1/2 -translate-x-1/2 w-20 h-1 rounded-full"
                    style={{ background: '#F97316' }}
                  />
                )}
              </button>
            );
          })}
        </div>

        {/* Articles */}
        {displayedArticles.length > 0 ? (
          displayedArticles.map((article, i) => (
            <ArticleCard key={article.id} article={article} index={i} />
          ))
        ) : (
          <div className="py-16 text-center" style={{ color: '#71767B' }}>
            <p className="text-lg mb-2">
              {activeTab === 'shared' ? 'Chưa chia sẻ bài viết nào' : 'Chưa thích bài viết nào'}
            </p>
            <p className="text-sm">Hãy khám phá và tương tác với các bài viết!</p>
          </div>
        )}
      </main>
      <RightPanel />
      <MobileNav />
    </div>
  );
}
